import{_ as e,o as a,c as o,ag as r}from"./chunks/framework.BZohXCq9.js";const g=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md"}'),n={name:"guide/index.md"};function i(s,t,d,l,h,c){return a(),o("div",null,[...t[0]||(t[0]=[r(`<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p><strong>ATLAST Protocol</strong> (Agent Trust Layer, Accountability Standards &amp; Transactions) is the trust infrastructure for the AI agent economy.</p><h2 id="what-problem-does-it-solve" tabindex="-1">What Problem Does It Solve? <a class="header-anchor" href="#what-problem-does-it-solve" aria-label="Permalink to &quot;What Problem Does It Solve?&quot;">​</a></h2><p>AI agents are increasingly autonomous — writing code, making decisions, managing workflows. But:</p><ul><li><strong>How do you know what an agent actually did?</strong> Not what it claims, but what it provably did.</li><li><strong>How do you verify an agent&#39;s work</strong> without re-running everything?</li><li><strong>How do you compare agents</strong> objectively, based on evidence rather than marketing?</li></ul><p>ATLAST Protocol answers all three questions with the <strong>Evidence Chain Protocol (ECP)</strong> — a cryptographic audit trail for every agent action.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Agent does work → ECP records input/output hashes → Links into chain → Signs with Ed25519</span></span>
<span class="line"><span>                                                                              ↓</span></span>
<span class="line"><span>                                                          Batch → Merkle Root → EAS on-chain</span></span></code></pre></div><p>Think of it as a <strong>dashcam for AI agents</strong>: it doesn&#39;t judge what the agent does, but it proves exactly what happened.</p><h2 id="three-layer-integration" tabindex="-1">Three-Layer Integration <a class="header-anchor" href="#three-layer-integration" aria-label="Permalink to &quot;Three-Layer Integration&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Layer</th><th>Effort</th><th>How</th></tr></thead><tbody><tr><td><strong>Layer 0</strong></td><td>Zero code</td><td><code>atlast run python my_agent.py</code> — transparent proxy</td></tr><tr><td><strong>Layer 1</strong></td><td>5 lines</td><td><code>from atlast_ecp import wrap</code> — SDK wrapper</td></tr><tr><td><strong>Layer 2</strong></td><td>10-20 lines</td><td>LangChain / CrewAI / AutoGen adapters</td></tr></tbody></table><h2 id="key-properties" tabindex="-1">Key Properties <a class="header-anchor" href="#key-properties" aria-label="Permalink to &quot;Key Properties&quot;">​</a></h2><ul><li><strong>Privacy</strong>: Content never leaves your device. Only SHA-256 hashes are transmitted.</li><li><strong>Tamper-proof</strong>: Chain hashes + Ed25519 signatures. Modifying any record breaks the chain.</li><li><strong>Verifiable</strong>: Anyone can verify a record&#39;s authenticity without the original content.</li><li><strong>Fail-Open</strong>: Recording failures never affect agent operation.</li><li><strong>Open Standard</strong>: MIT license, designed for ecosystem adoption.</li></ul>`,13)])])}const u=e(n,[["render",i]]);export{g as __pageData,u as default};
